// ---- 1. Pull in the two sources, preserving lineage ----
const groqResponse = $json;
const business = $('Website Check').item.json;

let parsed;

try {
  // ---- 2. Hunt for the actual text content across possible shapes ----
  const rawContent =
    groqResponse?.choices?.[0]?.message?.content ??
    groqResponse?.body?.choices?.[0]?.message?.content ??
    groqResponse?.choices?.[0]?.text ??
    groqResponse?.body?.choices?.[0]?.text ??
    null;

  if (!rawContent) {
    const apiError =
      groqResponse?.error?.message ||
      groqResponse?.body?.error?.message ||
      JSON.stringify(groqResponse).slice(0, 300);
    throw new Error(`No content found in Groq response. API said: ${apiError}`);
  }

  // ---- 3. Strip markdown code fences safely (```json ... ``` or ``` ... ```) ----
  const cleanContent = rawContent
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  parsed = JSON.parse(cleanContent);

} catch (e) {
  // ---- 4. Never crash the workflow - fall back to a safe, flagged record ----
  parsed = {
    fit_score: 0,
    pain_points: [],
    industry: 'Unknown',
    estimated_size: 'SMB',
    outreach_angle: `PARSE_ERROR: ${e.message}`
  };
}

const painPoints = Array.isArray(parsed.pain_points) ? parsed.pain_points : [];

// ---- 5. Normalize phone: prevent Google Sheets from reading "+..." as a formula ----
let phone = business.phone || business.phoneUnformatted || '';
if (typeof phone === 'string' && phone.startsWith('+')) {
  phone = `'${phone}`;
}

// ---- 6. Normalize review count across Apify's inconsistent field names ----
const reviewsCount =
  business.reviewsCount ??
  business.reviewCount ??
  business.totalReviews ??
  0;

// ---- 7. Merge everything into one clean, consistent record ----
return {
  json: {
    ...business,
    phone,
    reviewsCount,
    fit_score: Number(parsed.fit_score) || 0,
    pain_points: painPoints,
    pain_points_text: painPoints.join('; '),
    industry: parsed.industry || '',
    estimated_size: parsed.estimated_size || '',
    outreach_angle: parsed.outreach_angle || '',
    reason: painPoints.length ? painPoints.join('; ') : (parsed.outreach_angle || 'Low fit score')
  }
};

