// Read Sent History is now a guaranteed direct upstream dependency,
// so $input here IS the Sent History rows (safe to read immediately).
const sentHistory = $input.all().map(i => i.json);

const sentEmails = new Set(
  sentHistory.map(r => (r.Email || '').toString().toLowerCase().trim()).filter(Boolean)
);
const sentNames = new Set(
  sentHistory.map(r => (r['Business Name'] || '').toString().toLowerCase().trim()).filter(Boolean)
);

// Pull the actual Hot Prospects for this run from their source node explicitly,
// rather than relying on fragile pairedItem lineage through the reshuffled Sent History data.
const hotProspects = $('Append - Hot Prospects').all();

return hotProspects.map((item, idx) => {
  const d = item.json;
  const email = (d.Email || '').toString().toLowerCase().trim();
  const name = (d['Business Name'] || '').toString().toLowerCase().trim();
  const alreadySent = (email && sentEmails.has(email)) || (name && sentNames.has(name));
  return {
    json: {
      ...d,
      alreadySent
    },
    pairedItem: { item: idx }
  };
});

