const original = $('Not Already Sent?').item.json;
const groqResponse = $json;

let parsed;

try {
  const rawContent =
    groqResponse?.choices?.[0]?.message?.content ??
    groqResponse?.body?.choices?.[0]?.message?.content ??
    groqResponse?.choices?.[0]?.text ??
    groqResponse?.body?.choices?.[0]?.text ??
    null;

  if (!rawContent) {
    const apiError =
      groqResponse?.error?.message ||
      groqResponse?.body?.error?.message ||
      JSON.stringify(groqResponse).slice(0, 300);
    throw new Error(`No content found in Groq response. API said: ${apiError}`);
  }

  const cleanContent = rawContent
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  parsed = JSON.parse(cleanContent);
} catch (e) {
  parsed = {
    subject: 'Quick question for ' + (original['Business Name'] || 'your team'),
    body: 'Draft generation failed (' + e.message + '). Please write this email manually before sending.'
  };
}

return {
  json: {
    ...original,
    email_subject: parsed.subject || ('Quick question for ' + (original['Business Name'] || 'your team')),
    email_body: parsed.body || ''
  }
};

const d = $json;
const errMsg = (d.error && d.error.message) ? d.error.message : (d.message || 'Unknown Gmail send error');
return {
  json: {
    'Business Name': d['Business Name'] || '',
    'Category': d['Category'] || '',
    'Rating': d['Rating'] || '',
    'Review Count': d['Review Count'] || 0,
    'Phone': d['Phone'] || '',
    'Address': d['Address'] || '',
    'Website': d['Website'] || '',
    'Fit Score': d['Fit Score'] || '',
    'Reason': 'Email send failed: ' + errMsg
  }
};
